    "starter": "function findDeepestMax(arr) {\n  // Your code here\n}",
    "solution": "function findDeepestMax(arr) {\n  let maxDepth = 0;\n  let deepestValues = [];\n  \n  function traverse(item, depth) {\n    if (Array.isArray(item)) {\n      for (const el of item) {\n        traverse(el, depth + 1);\n      }\n    } else {\n      if (depth > maxDepth) {\n        maxDepth = depth;\n        deepestValues = [item];\n      } else if (depth === maxDepth) {\n        deepestValues.push(item);\n      }\n    }\n  }\n  \n  traverse(arr, 0);\n  return Math.max(...deepestValues);\n}",
