    "breakdown": "useLocalStorage — один з найпопулярніших custom hooks.\n\nКлючові моменти:\n1. Lazy initializer useState(() => ...) — виконується лише раз при монтуванні\n2. try/catch навколо localStorage — SSR або privacy mode можуть кидати помилки\n3. JSON.parse/stringify — localStorage зберігає лише рядки\n4. Functional update: typeof value === 'function' ? value(storedValue) : value — підтримка патерну setVal(prev => prev + 1)\n5. Повертаємо tuple [value, setter] — як useState, для зручної деструктуризації",
    "testCode": "// Мок localStorage\nconst _store = {};\nglobalThis.window = {\n  localStorage: {\n    getItem: (k) => _store[k] ?? null,\n    setItem: (k, v) => { _store[k] = v; },\n    removeItem: (k) => { delete _store[k]; }\n  }\n};\n\n// Мок useState\nlet _state;\nfunction useState(init) {\n  _state = typeof init === 'function' ? init() : init;\n  const set = (v) => { _state = typeof v === 'function' ? v(_state) : v; };\n  return [{ get val() { return _state; } }, set];\n}\n\ntest('reads initial value when localStorage empty', () => {\n  delete _store['test-key'];\n  assertEqual(_store['test-key'], undefined);\n  const fallback = 42;\n  const val = _store['test-key'] ? JSON.parse(_store['test-key']) : fallback;\n  assertEqual(val, 42);\n});\n\ntest('reads from localStorage if key exists', () => {\n  _store['theme'] = JSON.stringify('dark');\n  const val = JSON.parse(_store['theme']);\n  assertEqual(val, 'dark');\n});\n\ntest('setItem stores JSON serialized value', () => {\n  const obj = { count: 5 };\n  _store['data'] = JSON.stringify(obj);\n  const parsed = JSON.parse(_store['data']);\n  assertEqual(parsed.count, 5);\n});\n\ntest('functional updater works', () => {\n  let state = 1;\n  const setter = (v) => { state = typeof v === 'function' ? v(state) : v; };\n  setter(prev => prev + 10);\n  assertEqual(state, 11);\n});\n\ntest('returns tuple of [value, setter]', () => {\n  const arr = [1, (v) => v];\n  assertEqual(Array.isArray(arr), true);\n  assertEqual(arr.length, 2);\n});",
